function Max-WaterContainer {
    param (
        [Parameter(Mandatory=$true)]
        [System.Collections.Generic.List[int]]$height
    )

    # Initialize pointers
    $left = 0
    $right = $height.Count - 1

    # Initialize maxArea
    $maxArea = 0

    # Loop until the two pointers meet
    while ($left -lt $right) {
        # Calculate the height of the container
        $heightOfContainer = [math]::Min($height[$left], $height[$right])

        # Calculate the width of the container
        $widthOfContainer = $right - $left

        # Calculate the area of the container
        $currentArea = $heightOfContainer * $widthOfContainer

        # Update maxArea if the current area is greater
        if ($currentArea -gt $maxArea) {
            $maxArea = $currentArea
        }

        # Move the pointer that points to the shorter line inward
        if ($height[$left] -lt $height[$right]) {
            $left++
        } else {
            $right--
        }
    }

    # Return the maximum area found
    return $maxArea
}

