function Count-GoodIntegers {
    param (
        [Parameter(Mandatory=$true)]
        [string]$num1,

        [Parameter(Mandatory=$true)]
        [string]$num2,

        [Parameter(Mandatory=$true)]
        [int]$max_sum,

        [Parameter(Mandatory=$true)]
        [int]$min_sum
    )

    # Helper function to calculate the sum of digits of a number
    function Get-DigitSum {
        param (
            [int]$number
        )
        $sum = 0
        while ($number -gt 0) {
            $sum += $number % 10
            $number = [math]::Floor($number / 10)
        }
        return $sum
    }

    # Convert the string numbers to integers
    $start = [int]$num1
    $end = [int]$num2

    # Initialize the count of good integers
    $count = 0

    # Iterate through the range and count good integers
    for ($i = $start; $i -le $end; $i++) {
        $digitSum = Get-DigitSum -number $i
        if ($digitSum -ge $min_sum -and $digitSum -le $max_sum) {
            $count++
        }
    }

    # Return the count modulo 10^9 + 7
    return $count % ([math]::Pow(10, 9) + 7)
}

