function Transpose-File {
    param (
        [string]$FilePath = "file.txt"
    )

    # Read the content of the file line by line
    $lines = Get-Content -Path $FilePath

    # Split each line into its individual elements and collect them into a list of lists
    $columns = @()
    foreach ($line in $lines) {
        $elements = $line -split ' '
        $columns += $elements
    }

    # Transpose the list of lists
    $maxColumnLength = $columns.Count / $lines.Count
    $transposed = @()
    for ($i = 0; $i -lt $maxColumnLength; $i++) {
        $newRow = @()
        for ($j = 0; $j -lt $lines.Count; $j++) {
            $newRow += $columns[$j * $maxColumnLength + $i]
        }
        $transposed += ($newRow -join ' ')
    }

    # Write the transposed content back to the file
    $transposed -join "`n" | Set-Content -Path $FilePath
}

# Example usage:
# "1 2 3" | Set-Content file.txt
# "4 5 6" | Set-Content -Append file.txt
