    $dp = @(0) * ($N + 1)

    # Base case: There is one way to stay at the ground
    $dp[0] = 1

    # Fill the dp array
    for ($i = 1; $i -le $N; $i++) {
        for ($j = 1; $j -le $K; $j++) {
            if ($i -ge $j) {
                $dp[$i] = ($dp[$i] + $dp[$i - $j]) % 100003
            }
        }
    }

    # Return the number of ways to reach the top
    return $dp[$N]
}

