function Get-MaxPathSum {
    param (
        [Parameter(Mandatory=$true)]
        [int[][]]$pyramid
    )

    # Get the number of rows in the pyramid
    $rows = $pyramid.Length

    # Iterate from the second last row to the top row
    for ($i = $rows - 2; $i -ge 0; $i--) {
        for ($j = 0; $j -le $i; $j++) {
            # Update the current element to be the sum of itself and the maximum of its two children
            $pyramid[$i][$j] += [math]::Max($pyramid[$i + 1][$j], $pyramid[$i + 1][$j + 1])
        }
    }

    # The top element now contains the maximum path sum
    return $pyramid[0][0]
}

