        )
        $isPrime = @(0..$limit) | ForEach-Object { $true }
        $isPrime[0] = $isPrime[1] = $false
        for ($i = 2; $i * $i -le $limit; $i++) {
            if ($isPrime[$i]) {
                for ($j = $i * $i; $j -le $limit; $j += $i) {
